import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { register as registerService } from '../services/authService';
import { useAuth } from '../context/AuthContext';

const Register = () => {
  const navigate = useNavigate();
  const { login } = useAuth();
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);

  const validate = () => {
    const errs = {};
    if (!formData.name || formData.name.length < 2) errs.name = 'Name must be at least 2 characters';
    if (!formData.email) errs.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(formData.email)) errs.email = 'Enter a valid email';
    if (!formData.password || formData.password.length < 6) errs.password = 'Password must be at least 6 characters';
    if (formData.password !== formData.confirmPassword) errs.confirmPassword = 'Passwords do not match';
    return errs;
  };

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    if (errors[e.target.name]) setErrors((prev) => ({ ...prev, [e.target.name]: '' }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) return setErrors(errs);

    setLoading(true);
    try {
      const { confirmPassword, ...payload } = formData;
      const userData = await registerService(payload);
      login(userData);
      toast.success(`Account created! Welcome, ${userData.name} 🎉`);
      navigate('/');
    } catch (err) {
      const msg = err.response?.data?.message || 'Registration failed. Try again.';
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  const InputField = ({ id, label, type = 'text', placeholder, field }) => (
    <div className="form-group">
      <label className="form-label" htmlFor={id}>{label}</label>
      <input
        type={type}
        id={id}
        name={field}
        className="form-input"
        placeholder={placeholder}
        value={formData[field]}
        onChange={handleChange}
        style={errors[field] ? { borderColor: 'var(--error)' } : {}}
      />
      {errors[field] && <p className="form-error">⚠ {errors[field]}</p>}
    </div>
  );

  return (
    <div className="auth-container">
      <div className="auth-card fade-in">
        <div className="auth-header">
          <div className="auth-logo">✨</div>
          <h1 className="auth-title">Create Account</h1>
          <p className="auth-subtitle">Join EduFeedback as a student</p>
        </div>

        <form onSubmit={handleSubmit} id="register-form" noValidate>
          <InputField id="reg-name" label="Full Name" placeholder="John Doe" field="name" />
          <InputField id="reg-email" label="Email Address" type="email" placeholder="john@college.edu" field="email" />
          <InputField id="reg-password" label="Password" type="password" placeholder="Min. 6 characters" field="password" />
          <InputField id="reg-confirm" label="Confirm Password" type="password" placeholder="Repeat your password" field="confirmPassword" />

          <button
            type="submit"
            id="register-submit"
            className="btn btn-primary btn-full btn-lg"
            disabled={loading}
          >
            {loading ? (
              <>
                <div className="spinner spinner-sm"></div>
                Creating account...
              </>
            ) : (
              '🎓 Create Account'
            )}
          </button>
        </form>

        <p className="auth-link" style={{ marginTop: '20px' }}>
          Already have an account? <Link to="/login">Sign in</Link>
        </p>
      </div>
    </div>
  );
};

export default Register;
